python3 -c "
import pandas as pd
import glob
for f in sorted(glob.glob('/app/*.csv')):
    try:
        df = pd.read_csv(f, nrows=2)
        print(f'{f}: {list(df.columns)}')
    except Exception as e:
        print(f'{f}: {e}')
"

python3 -c "
import pandas as pd
import glob
for f in sorted(glob.glob('/app/*.csv')):
